import hashlib
import hmac
import json
import os
from flask import Flask, request, jsonify
from functools import wraps

app = Flask(__name__)

# Configuration
WEBHOOK_SECRET = os.environ.get('WEBHOOK_SECRET')
ALLOWED_PARTNERS = set(os.environ.get('ALLOWED_PARTNERS', '').split(','))

def validate_signature(request):
    """Validate webhook signature"""
    if not WEBHOOK_SECRET:
        return False
    
    signature = request.headers.get('X-Signature')
    if not signature:
        return False
    
    payload = request.get_data()
    
    expected_signature = hmac.new(
        WEBHOOK_SECRET.encode('utf-8'),
        payload,
        hashlib.sha256
    ).hexdigest()
    
    return hmac.compare_digest(signature, expected_signature)

def validate_partner(request):
    """Validate partner is allowed"""
    partner_id = request.headers.get('X-Partner-ID')
    if not partner_id or partner_id not in ALLOWED_PARTNERS:
        return False
    return True

def webhook_required(f):
    """Decorator to validate webhook requests"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if not validate_signature(request):
            return jsonify({'error': 'Invalid signature'}), 401
        
        if not validate_partner(request):
            return jsonify({'error': 'Unauthorized partner'}), 403
            
        return f(*args, **kwargs)
    return decorated_function

@app.route('/webhook/payment', methods=['POST'])
@webhook_required
def payment_webhook():
    """Handle payment webhook events"""
    try:
        event_data = request.get_json()
        
        if not event_data:
            return jsonify({'error': 'Invalid JSON'}), 400
        
        # Process payment event
        event_type = event_data.get('event_type')
        payment_id = event_data.get('payment_id')
        status = event_data.get('status')
        
        # Validate required fields
        if not all([event_type, payment_id, status]):
            return jsonify({'error': 'Missing required fields'}), 400
        
        # Log the event (in production, use proper logging)
        print(f"Processing {event_type} for payment {payment_id} with status {status}")
        
        # TODO: Implement actual payment processing logic here
        # This could include updating database, sending notifications, etc.
        
        return jsonify({'status': 'success', 'message': 'Event processed'}), 200
        
    except Exception as e:
        print(f"Error processing webhook: {str(e)}")
        return jsonify({'error': 'Internal server error'}), 500

